import {
    Link,
    useLocation,
    Outlet
} from "react-router-dom"


/* 
outlet 은 정의한 router에서 특정 path에 
해당하는 경로에 children이 있을때 
해당 컴포넌트를 렌더링하도록 해주는 컴포넌트이다

반드시 부모 컴포넌트내에서 정의해줘야함
*/

import $ from 'jquery';
export function Header() {
    return (
        <div>
            <h1>
                <Link to='/'>
                WEBSITE
                </Link>
            </h1>
        </div>
    )
}
export function Navigation() {
    
    $(function(){
        $("nav >a").on("mouseenter",function(){
            $(this).find("ul").stop().slideDown(500);
        });
        $("nav>a").on("mouseleave",function(){
            $(this).find("ul").stop().slideUp(500);
        });
    });


    return (
        <div className="menu">
            <nav>
                <Link className="ff" to="about">About
                <ul>
                <li><Link to="about/history">History</Link></li>
                <li><Link to="about/location">Location</Link></li>
                </ul>
                </Link>
                <Link className="ff" to="events">Events
                <ul>
                <li><Link to="events/list1">List1</Link></li>
                <li><Link to="events/list2">List2</Link></li>
                <li><Link to="events/list3">List3</Link></li>
                </ul>
                </Link>
                <Link to="products">Products</Link>
                <Link to="contact">Contact Us</Link>
            </nav>
        </div>
    )
}
